import json

ASR_CONFIDENCE_THRESHOLDS = {
    "high": 0.85,   # Act immediately, no confirmation needed
    "medium": 0.65, # Confirm by reading back the transcript
    "low": 0.40,    # Ask the user to rephrase
    # Below 0.40: treat as no speech detected
}

def handle_asr_result(asr_result: dict, intent_context: str) -> dict:
    """
    Returns a structured action dict for the dialog manager.
    asr_result: {"transcript": str, "confidence": float, "noise_level_db": float}
    """
    transcript = asr_result.get("transcript", "").strip()
    confidence = asr_result.get("confidence", 0.0)
    noise_db = asr_result.get("noise_level_db", 0.0)

    # High ambient noise: lower effective confidence
    if noise_db > 65:  # 65 dB ~ busy office / street
        confidence *= 0.85

    if not transcript or confidence < 0.40:
        return {
            "action": "timeout_reprompt",
            "response": "I didn't catch that. <break time='300ms'/> Could you try again?",
        }

    if confidence < ASR_CONFIDENCE_THRESHOLDS["low"]:
        return {
            "action": "clarify",
            "response": f"I heard '{transcript}'. <break time='200ms'/> Is that right? Say yes or no.",
            "pending_transcript": transcript,
        }

    if confidence < ASR_CONFIDENCE_THRESHOLDS["medium"]:
        return {
            "action": "confirm_and_proceed",
            "response": f"Got it — '{transcript}'. <break time='150ms'/> Proceeding.",
            "transcript": transcript,
        }

    # High confidence: act directly
    return {
        "action": "proceed",
        "transcript": transcript,
        "confidence": confidence,
    }


def demo():
    noisy_result = {"transcript": "set timer five minuets", "confidence": 0.58, "noise_level_db": 72}
    action = handle_asr_result(noisy_result, intent_context="timer")
    print(json.dumps(action, indent=2))
    # Output: action="clarify", reads back transcript for user confirmation

demo()
